create or replace function public.get_operations_health()returns jsonb language plpgsql stable security definer set search_path=public as $$declare result jsonb;begin if auth.uid()is null or not public.is_staff()then raise exception'Staff access required';end if;select jsonb_build_object('generatedAt',now(),'redemptions',jsonb_build_object('submitted',count(*)filter(where status='submitted'),'approved',count(*)filter(where status='approved'),'aging',count(*)filter(where status in('submitted','approved')and created_at<now()-interval'2 days')),'support',jsonb_build_object('open',(select count(*)from public.support_tickets where status not in('resolved','closed')),'awaitingStaff',(select count(*)from public.support_tickets where status='awaiting_staff'),'aging',(select count(*)from public.support_tickets where status not in('resolved','closed')and last_activity_at<now()-interval'2 days')),'reseller',jsonb_build_object('awaitingReview',(select count(*)from public.verification_requests where status in('submitted','needs_information'))),'imports',jsonb_build_object('failed',(select count(*)from public.import_runs where status='failed'),'unresolvedRows',(select count(*)from public.import_staged_rows where validation_status in('invalid','unresolved')),'latestSuccess',(select max(completed_at)from public.import_runs where status='completed')),'notifications',jsonb_build_object('emailEnabled',coalesce((select email_enabled from public.notification_channel_settings where id='default'),false),'failed',(select count(*)from public.notification_deliveries where status='failed'),'suppressed',(select count(*)from public.notification_deliveries where status='suppressed')),'audit',jsonb_build_object('last24Hours',(select count(*)from public.audit_events where occurred_at>now()-interval'24 hours'),'recent',coalesce((select jsonb_agg(jsonb_build_object('id',x.id,'eventType',x.event_type,'entityType',x.entity_type,'entityId',x.entity_id,'occurredAt',x.occurred_at,'actor',x.actor)order by x.occurred_at desc)from(select a.id,a.event_type,a.entity_type,a.entity_id,a.occurred_at,coalesce(p.display_name,'System')actor from public.audit_events a left join public.profiles p on p.id=a.actor_profile_id order by a.occurred_at desc limit 10)x),'[]'::jsonb)))into result from public.redemption_requests;return result;end$$;revoke execute on function public.get_operations_health()from public,anon;grant execute on function public.get_operations_health()to authenticated;
